// 1. Sadə Async/Await
function checkFuel() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve("Yanacaq yoxlanıldı, hazırdır!");
      } else {
        reject("Yanacaq sızması aşkarlandı!");
      }
    }, 2000);
  });
}

async function launchMission() {
  try {
    console.log("Missiya başlayır...");
    let fuelStatus = await checkFuel();
    console.log(fuelStatus);
    console.log("Buraxılış uğurludur!");
  } catch (error) {
    console.log(`Səhv: ${error}`);
  }
}

launchMission();
// nəticə (ehtimala görə):
// Missiya başlayır...
// (2 saniyə sonra) Yanacaq yoxlanıldı, hazırdır!
// Buraxılış uğurludur!
// və ya: Səhv: Yanacaq sızması aşkarlandı!

// 2. Çoxlu Await ilə zəncir
async function prepareMission() {
  try {
    console.log("Missiyaya hazırlıq...");
    let fuel = await checkFuel();
    console.log(fuel);
    let astronauts = await new Promise(resolve => {
      setTimeout(() => resolve("Astronavtlar hazırdır!"), 1500);
    });
    console.log(astronavts);
    console.log("Missiya hazırdır!");
  } catch (error) {
    console.log(`Səhv: ${error}`);
  }
}

prepareMission();
// nəticə:
// Missiyaya hazırlıq...
// Yanacaq yoxlanıldı, hazırdır!
// Astronavtlar hazırdır!
// Missiya hazırdır!

// 3. Promise.all ilə Async/Await
function checkOrbit() {
  return new Promise(resolve => {
    setTimeout(() => resolve("Orbit yoxlanıldı!"), 1000);
  });
}

async function fullMissionCheck() {
  try {
    let results = await Promise.all([checkFuel(), checkOrbit()]);
    console.log("Nəticələr: ", results);
  } catch (error) {
    console.log(`Səhv: ${error}`);
  }
}

fullMissionCheck();
// nəticə: Nəticələr: ["Yanacaq yoxlanıldı, hazırdır!", "Orbit yoxlanıldı!"]

// 4. API ilə istifadə
async function fetchMissionData() {
  try {
    let response = await fetch("https://api.example.com/mission-data");
    let data = await response.json();
    console.log("Missiya məlumatları: ", data);
  } catch (error) {
    console.log("Server səhvi: ", error);
  }
}

fetchMissionData();
// nəticə: API-dən asılı olaraq məlumatlar və ya səhv

// Səhv idarəetməsiz nümunə
async function riskyLaunch() {
  let result = await new Promise((resolve, reject) => {
    reject("Raketin mühərriki xarab oldu!");
  });
  console.log(result);
}

riskyLaunch().catch(error => console.log(`Səhv: ${error}`));
// nəticə: Səhv: Raketin mühərriki xarab oldu!

// Paralel tapşırıqlar
async function checkAllSystems() {
  try {
    let [fuel, orbit] = await Promise.all([
      checkFuel(),
      checkOrbit()
    ]);
    console.log(`Sistemlər hazır: ${fuel}, ${orbit}`);
  } catch (error) {
    console.log(`Səhv: ${error}`);
  }
}

checkAllSystems();
// nəticə: Sistemlər hazır: Yanacaq yoxlanıldı, hazırdır!, Orbit yoxlanıldı!

