function checkFuel() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve("Fuel checked, ready!");
      } else {
        reject("Fuel leak detected!");
      }
    }, 2000);
  });
}

async function launchMission() {
  try {
    console.log("Mission starting...");
    let fuelStatus = await checkFuel();
    console.log(fuelStatus);
    console.log("Launch successful!");
  } catch (error) {
    console.log(`Error: ${error}`);
  }
}

launchMission();
// Output (depending on chance):
// Mission starting...
// (2 seconds later) Fuel checked, ready!
// Launch successful!
// or: Error: Fuel leak detected!

