// 1. Простой Async/Await
function checkFuel() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (Math.random() > 0.2) {
        resolve("Топливо проверено, готово!");
      } else {
        reject("Обнаружена утечка топлива!");
      }
    }, 2000);
  });
}

async function launchMission() {
  try {
    console.log("Миссия начинается...");
    let fuelStatus = await checkFuel();
    console.log(fuelStatus);
    console.log("Запуск успешен!");
  } catch (error) {
    console.log(`Ошибка: ${error}`);
  }
}

launchMission();
// Вывод (в зависимости от шанса):
// Миссия начинается...
// (2 секунды спустя) Топливо проверено, готово!
// Запуск успешен!
// или: Ошибка: Обнаружена утечка топлива!

// 2. Цепочка из нескольких Await
function prepareMission() {
  try {
    console.log("Подготовка миссии...");
    let fuel = await checkFuel();
    console.log(fuel);
    let astronauts = await new Promise(resolve => {
      setTimeout(() => resolve("Астронавты готовы!"), 1500);
    });
    console.log(astronauts);
    console.log("Миссия готова!");
  } catch (error) {
    console.log(`Ошибка: ${error}`);
  }
}

prepareMission();
// Вывод:
// Подготовка миссии...
// Топливо проверено, готово!
// Астронавты готовы!
// Миссия готова!

// 3. Async/Await с Promise.all
function checkOrbit() {
  return new Promise(resolve => {
    setTimeout(() => resolve("Орбита проверена!"), 1000);
  });
}

async function fullMissionCheck() {
  try {
    let results = await Promise.all([checkFuel(), checkOrbit()]);
    console.log("Результаты: ", results);
  } catch (error) {
    console.log(`Ошибка: ${error}`);
  }
}

fullMissionCheck();
